// Normalize results from both Amadeus and SerpApi into unified schema
const allItems = $input.all();
const normalizedFlights = [];

for (const item of allItems) {
  const data = item.json;

  // --- Normalize Amadeus results ---
  if (data.data && Array.isArray(data.data)) {
    for (const offer of data.data) {
      try {
        const itinerary = offer.itineraries?.[0];
        const segments = itinerary?.segments || [];
        const lastSeg = segments[segments.length - 1];
        const firstSeg = segments[0];

        // Parse duration (e.g. PT14H30M)
        const durStr = itinerary?.duration || 'PT0H';
        const durHours = parseInt(durStr.match(/([0-9]+)H/)?.[1] || 0);
        const durMins = parseInt(durStr.match(/([0-9]+)M/)?.[1] || 0);
        const totalMinutes = durHours * 60 + durMins;

        normalizedFlights.push({
          source: 'Amadeus',
          airline: offer.validatingAirlineCodes?.[0] || 'N/A',
          flightNumbers: segments.map(s => `${s.carrierCode}${s.number}`).join(', '),
          price: parseFloat(offer.price?.grandTotal || 0),
          currency: offer.price?.currency || 'USD',
          stops: segments.length - 1,
          totalDurationMinutes: totalMinutes,
          totalDurationFormatted: `${durHours}h ${durMins}m`,
          departureTime: firstSeg?.departure?.at || '',
          departureAirport: firstSeg?.departure?.iataCode || '',
          arrivalTime: lastSeg?.arrival?.at || '',
          arrivalAirport: lastSeg?.arrival?.iataCode || '',
          cabinClass: offer.travelerPricings?.[0]?.fareDetailsBySegment?.[0]?.cabin || 'ECONOMY',
          seatsAvailable: offer.numberOfBookableSeats || null,
          offerId: offer.id
        });
      } catch(e) {
        // skip malformed entry
      }
    }
  }

  // --- Normalize SerpApi / Google Flights results ---
  if (data.best_flights && Array.isArray(data.best_flights)) {
    for (const flight of data.best_flights) {
      try {
        const leg = flight.flights?.[0];
        const lastLeg = flight.flights?.[flight.flights.length - 1];
        normalizedFlights.push({
          source: 'Google Flights',
          airline: leg?.airline || 'N/A',
          flightNumbers: flight.flights?.map(f => f.flight_number).join(', ') || '',
          price: parseFloat(flight.price || 0),
          currency: 'USD',
          stops: (flight.flights?.length || 1) - 1,
          totalDurationMinutes: flight.total_duration || 0,
          totalDurationFormatted: `${Math.floor((flight.total_duration||0)/60)}h ${(flight.total_duration||0)%60}m`,
          departureTime: leg?.departure_airport?.time || '',
          departureAirport: leg?.departure_airport?.id || '',
          arrivalTime: lastLeg?.arrival_airport?.time || '',
          arrivalAirport: lastLeg?.arrival_airport?.id || '',
          cabinClass: 'ECONOMY',
          seatsAvailable: null,
          offerId: `serpapi_${flight.price}_${leg?.flight_number}`
        });
      } catch(e) {
        // skip malformed entry
      }
    }
  }

  if (data.other_flights && Array.isArray(data.other_flights)) {
    for (const flight of data.other_flights) {
      try {
        const leg = flight.flights?.[0];
        const lastLeg = flight.flights?.[flight.flights.length - 1];
        normalizedFlights.push({
          source: 'Google Flights',
          airline: leg?.airline || 'N/A',
          flightNumbers: flight.flights?.map(f => f.flight_number).join(', ') || '',
          price: parseFloat(flight.price || 0),
          currency: 'USD',
          stops: (flight.flights?.length || 1) - 1,
          totalDurationMinutes: flight.total_duration || 0,
          totalDurationFormatted: `${Math.floor((flight.total_duration||0)/60)}h ${(flight.total_duration||0)%60}m`,
          departureTime: leg?.departure_airport?.time || '',
          departureAirport: leg?.departure_airport?.id || '',
          arrivalTime: lastLeg?.arrival_airport?.time || '',
          arrivalAirport: lastLeg?.arrival_airport?.id || '',
          cabinClass: 'ECONOMY',
          seatsAvailable: null,
          offerId: `serpapi_other_${flight.price}_${leg?.flight_number}`
        });
      } catch(e) {
        // skip malformed entry
      }
    }
  }
}

// Deduplicate by price + airline + departure
const seen = new Set();
const deduped = normalizedFlights.filter(f => {
  const key = `${f.airline}_${f.price}_${f.departureTime}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

return deduped.map(f => ({ json: f }));

// Score and rank flights
// Lower score = better option
const flights = $input.all().map(item => {
  const f = item.json;

  // Weighted score: price (60%), stops penalty (25%), duration (15%)
  const priceScore = f.price * 0.6;
  const stopsScore = f.stops * 80; // penalty per stop
  const durationScore = (f.totalDurationMinutes / 60) * 3;
  const score = priceScore + stopsScore + durationScore;

  return {
    json: {
      ...f,
      score: Math.round(score),
      valueRating: f.stops === 0 ? 'Direct' : f.stops === 1 ? '1 Stop' : `${f.stops} Stops`
    }
  };
});

// Sort by score ascending (best value first)
flights.sort((a, b) => a.json.score - b.json.score);

return flights;

// Build final structured output
const ranked = $input.all().map(i => i.json);

if (ranked.length === 0) {
  return [{
    json: {
      success: false,
      message: 'No flights found matching your criteria.',
      totalFound: 0,
      cheapestOption: null,
      bestValueOption: null,
      directFlights: [],
      topResults: [],
      searchedAt: new Date().toISOString()
    }
  }];
}

// Cheapest by price
const byPrice = [...ranked].sort((a, b) => a.price - b.price);
const cheapest = byPrice[0];

// Best value (lowest score = best combo of price + speed + stops)
const bestValue = ranked[0]; // already sorted by score

// Direct flights only
const directFlights = ranked.filter(f => f.stops === 0).slice(0, 5);

// Top 10 overall
const topResults = ranked.slice(0, 10);

// Summary stats
const prices = ranked.map(f => f.price);
const avgPrice = prices.reduce((a,b) => a+b, 0) / prices.length;
const minPrice = Math.min(...prices);
const maxPrice = Math.max(...prices);

return [{
  json: {
    success: true,
    totalFound: ranked.length,
    summary: {
      cheapestPrice: minPrice,
      mostExpensivePrice: maxPrice,
      averagePrice: Math.round(avgPrice),
      currency: ranked[0]?.currency || 'USD',
      directFlightsAvailable: directFlights.length > 0
    },
    cheapestOption: cheapest,
    bestValueOption: bestValue,
    directFlights: directFlights,
    topResults: topResults,
    searchedAt: new Date().toISOString()
  }
}];

