const tasks = $input.all();
const targetTaskName = $node["Edit Fields"].json.taskName;
const rawDate = $node["Edit Fields"].json.dueDate;

// 2. Perform the search
const match = tasks.find(t => t.json.name === targetTaskName);

// 3. If NOT found, return a "not found" object
if (!match) {
  return [{ 
    json: { 
      found: false, 
      message: `Task "${targetTaskName}" was not in the list of ${tasks.length} items.`,
      targetName: targetTaskName
    } 
  }];
}

// 4. If found, calculate the Date
let clickUpTimestamp = null;

if (rawDate) {
  try {
    // Use n8n's internal Luxon DateTime to parse natural language
    // .fromText() is the most powerful way to handle "tomorrow", "next Friday", etc.
    clickUpTimestamp = $fromText(rawDate).toMillis();
  } catch (e) {
    // If parsing fails, we set it to null so the workflow doesn't crash
    clickUpTimestamp = null;
  }
}

// 5. Return the merged data
return [{ 
  json: { 
    found: true,
    id: match.json.id, 
    name: match.json.name,
    dueDateTimestamp: clickUpTimestamp, // Use this in your ClickUp node
    originalDateInput: rawDate
  } 
}];

