// This processes every item in the batch (Multiple Items from Email Trigger)
return $input.all().flatMap(item => {
  const textContent = item.json.content?.[0]?.text ?? "";

  let extractedDataList = [];

  // 1. Try to extract from JSON block
  const jsonMatch = textContent.match(/```json\n([\s\S]*?)```/);
  if (jsonMatch) {
    try {
      const parsed = JSON.parse(jsonMatch[1]);
      extractedDataList = Array.isArray(parsed) ? parsed : [parsed];
    } catch (e) {
      extractedDataList = [{}];
    }
  } else {
    extractedDataList = [{}];
  }

  // 2. Fallback Helper: Regex extraction
  const getValue = (fieldName) => {
    const regex = new RegExp(`(?:\\|\\s*(?:\\*\\*|\\s*\`)${fieldName}(?:\\*\\*|\`\\s*)\\s*\\|\\s*|"${fieldName}"\\s*:\\s*"?)([^"\\|,\\n\\}]*)`, 'i');
    const match = textContent.match(regex);
    return (match && match[1].trim() !== "null") ? match[1].trim().replace(/^"|"$/g, '') : null;
  };

  return extractedDataList.map(data => {
    // Helper to prioritize JSON data, then Regex, then literal null
    const mapField = (key) => {
      if (data[key] !== undefined) return data[key];
      return getValue(key); 
    };

    return {
      json: {
        type: mapField('type'),
        invoice_number: mapField('invoice_number'),
        invoice_description: mapField('invoice_description'),
        issue_date: mapField('issue_date'),
        issuer_name: mapField('issuer_name'),
        issuer_email: mapField('issuer_email'),
        recipient_name: mapField('recipient_name'),
        recipient_email: mapField('recipient_email'),
        account_number: mapField('account_number'),
        // Maintain null for items, otherwise stringify array
        item: Array.isArray(data.item) ? JSON.stringify(data.item) : (data.item ?? getValue('item')),
        item_price: mapField('item_price'),
        amount: mapField('amount'),
        vat: mapField('vat'),
        discount: mapField('discount'),
        currency: mapField('currency'),
        file_link: mapField('file_link'),
        has_attachment: !!(item.json.attachments && item.json.attachments.length > 0)
      }
    };
  });
});

