// Parse and enrich activity data
const activity = $input.first().json;

// Helper: meters to km
const toKm = (m) => (m / 1000).toFixed(2);
// Helper: meters to miles
const toMiles = (m) => (m / 1609.34).toFixed(2);
// Helper: seconds to HH:MM:SS
const toTime = (s) => {
  const h = Math.floor(s / 3600);
  const m = Math.floor((s % 3600) / 60);
  const sec = s % 60;
  return [h, m, sec].map(v => String(v).padStart(2, '0')).join(':');
};
// Helper: m/s to min/km pace
const toPace = (mps) => {
  if (!mps || mps === 0) return 'N/A';
  const secPerKm = 1000 / mps;
  const min = Math.floor(secPerKm / 60);
  const sec = Math.round(secPerKm % 60);
  return `${min}:${String(sec).padStart(2, '0')} /km`;
};

const type = activity.type || activity.sport_type || 'Workout';
const distanceKm = toKm(activity.distance || 0);
const distanceMi = toMiles(activity.distance || 0);
const movingTime = toTime(activity.moving_time || 0);
const elevationGain = Math.round(activity.total_elevation_gain || 0);
const avgSpeed = activity.average_speed || 0;
const pace = toPace(avgSpeed);
const avgHR = activity.average_heartrate ? Math.round(activity.average_heartrate) : null;
const calories = activity.calories || null;
const name = activity.name || type;
const date = new Date(activity.start_date_local || activity.start_date).toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

// Pick emoji for sport type
