const quoteList = quotes[type] || quotes.default;
const quote = quoteList[Math.floor(Math.random() * quoteList.length)];

// Build tweet text
let tweet = `${emoji} ${type} Complete! ${emoji}\n\n`;
tweet += `📅 ${date}\n`;
tweet += `🏷️ ${name}\n\n`;

if (activity.distance > 0) {
  tweet += `📏 Distance: ${distanceKm} km (${distanceMi} mi)\n`;
}
tweet += `⏱️ Time: ${movingTime}\n`;

if (type === 'Run' || type === 'Walk' || type === 'Hike') {
  tweet += `🐾 Pace: ${pace}\n`;
}
